struct MeasurementData {
    uint32_t sensor_id;
    std::vector<float> temperatures;
    double pressure;

    void serialise(auto& adaptor) const {
        // Serialization: write sensor_id directly, convert temperatures and pressure to little-endian
        adaptor.write(sensor_id);

        for (const auto& temp : temperatures) {
            float converted = hexi::endian::conditional_reverse(temp, 
                                                               std::endian::native, 
                                                               std::endian::little);
            adaptor.write(converted);
        }

        double converted_pressure = hexi::endian::conditional_reverse(pressure, 
                                                                     std::endian::native, 
                                                                     std::endian::little);
        adaptor.write(converted_pressure);
    }

    void deserialise(auto& adaptor) {
        // Deserialization: read sensor_id directly, read temperatures and pressure with in-place conversion
        adaptor.read(sensor_id);

        // Read temperatures with in-place conversion
        for (auto& temp : temperatures) {
            float f;
            adaptor.read(f);
            hexi::endian::little_to_native_inplace(f);
            temp = f;
        }

        // Read pressure with in-place conversion
        double p;
        adaptor.read(p);
        hexi::endian::little_to_native_inplace(p);
        pressure = p;
    }
};

